INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'ADMINISTRADOR DE SISTEMAS', 'Administrador de Sistemas', 'Vacante / Por asignar', 'ADMINISTRADOR', 'operative', 'Garantizar el correcto funcionamiento, mantenimiento y seguridad de la infraestructura tecnológica de la empresa. Administrar servidores, redes y sistemas informáticos, así como ofrecer soporte técnico a los usuarios internos.', '["Administrar servidores y redes.","Monitorear el desempeño de la infraestructura tecnológica.","Implementar y dar mantenimiento a sistemas.","Realizar respaldos y planes de recuperación.","Brindar soporte técnico a usuarios.","Garantizar la seguridad informática.","Documentar procedimientos."]'::jsonb, '{"education":"Licenciatura o Ingeniería","experience":"Deseable 1 año","specialty":"Tecnologías de la Información, Redes, Seguridad Informática","languages":"Español, deseable Inglés técnico nivel B1-B2 MCRE","knowledge":"Administración de sistemas operativos (Windows, Linux), redes LAN/WAN, firewalls, respaldos, virtualización (VMware, Hyper-V), servicios en la nube, ciberseguridad, Active Directory, herramientas de monitoreo.","skills":"Capacidad analítica. \r\nResolución de problemas.\r\n Atención al cliente.\r\n Trabajo bajo presión.\r\n Organización.\r\n Documentación técnica.\r\n Trabajo en equipo.","travel":"Si","sex":"Indistinto"}'::jsonb, 'DISEÑADOR Y DESARROLLADOR WEB', 'PROC_FINANZAS')
