INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'APLICADOR', 'Aplicador', 'Vacante / Por asignar', 'APLICADOR', 'operative', 'Aplicar exámenes de manera profesional y capacitada para logra el trabajo de la manera 
más eficiente de tal forma que se cumpla con los estándares de Cambridge y con otras casa certificadoras del idioma de inglés, con el fin de lograr la satisfacción de nuestros clientes.', '["Mantener la confidencialidad del material del examen y asegurar su custodia segura antes y después de su administración.","Familiarizarse y cumplir con los manuales y directrices proporcionados por Cambridge  u otras casas certificadoras para la administración de exámenes.","Tratar a todos los candidatos de manera justa y equitativa, sin mostrar favoritismo ni discriminación.","Estar familiarizado con los procedimientos del examen, asegurando que se sigan adecuadamente y que los candidatos reciban las instrucciones necesarias.","Conocer el material del examen y ser capaz de utilizar las instrucciones y recursos proporcionados de manera efectiva durante su administración.","Aplicar los criterios de evaluación establecidos de manera consistente y justa al evaluar el desempeño de los candidatos.","Mantener un comportamiento profesional, actuar con respeto y cortesía hacia los candidatos.","Apoyar y mostrar flexibilidad en la organización y logística de los exámenes, adaptándose a las necesidades y circunstancias particulares.                                                                              Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso.","Colaborar en la participación de los alumnos con discapacidad.","Potenciar el desarrollo de las capacidades de los alumnos con necesidades educativas especiales.","Promover la inclusión de los alumnos con necesidades específicas","Ofrecer recursos para adaptar y mejorar proceso de aprendizaje.","Garantizar el enfoque a los estudiantes, partes interesadas durante la aplicacion de examenes.","Mantener una comunicacion acertivamente con coordinacion de Examenes, Gerencia de Proyectos y partes interesadas."]'::jsonb, '{"education":"Licenciatura o Carrera Trunca","experience":"N/A","specialty":"Enseñanza del Inglés o afín","languages":"Español, Nivel deseable Ingles B2 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Comprensión de las directrices y manuales relacionados con los exámenes de evaluación del inglés.\r\nFamiliaridad con los procedimientos y requisitos específicos de cada examen, así como el uso adecuado del material y las instrucciones proporcionadas.\r\nComprensión de los criterios de evaluación utilizados en los exámenes y capacidad para aplicarlos de manera justa y coherente.\r\nDe las normas de confidencialidad y ética relacionadas con la administración de exámenes.                                    Conocimientos sobre los recursos relativos a la atención a personas con discapacidad.\r\nConocimientos sobre las posibles barreras de participación de los alumnos con discapacidad.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams o Zoom.\r\nManejo de herramientas de presentación como Google Slides o Prezi.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"Si","sex":"Indistinto"}'::jsonb, 'COORDINADORA DE EXÁMENES', NULL)
