    process_id = EXCLUDED.process_id,
    updated_at = NOW();

INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'ASISTENTE ADMINISTRATIVO', 'Asistente Administrativo', 'Vacante / Por asignar', 'ASISTENTE', 'operative', 'Proveer servicio al cliente de calidad para apoyar al logro de objetivos y metas de la empresa. Apoyar en actividades administrativas básicas con excelente actitud.', '["Atención a clientes","Seguimiento a llamadas telefónicas / correos","Seguimiento a quejas/dudas de clientes","Entrega de certificados/ manejo de documentación","Emisión de facturas","Seguimiento a pago de facturas","Registro de movimientos contables","Atender auditorías aplicables","Participar en las actividades de ESR que se le asignen                                                                                               Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Preparatoria / Carrera Trunca","experience":"","specialty":"Contabilidad, Administración, Informática o afín","languages":"Español, Nivel deseable Ingles A1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Comprensión de los sistemas de archivo y los procesos de retención de registros.\r\nComprension básica de la contabilidad, lo que puede incluir la facturación, la gestión de gastos y la preparación de informes financieros.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams, o Zoom.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)\r\nManejo de herramientas contables como AdminTotal","travel":"","sex":""}'::jsonb, NULL, NULL)
