INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'ASISTENTE LEC BC', 'Asistente LEC BC', 'Vacante / Por asignar', 'ASISTENTE', 'operative', 'Brindar apoyo administrativo, operativo y logístico a la coordinación de LEC BC, facilitando el desarrollo eficiente de actividades académicas, administrativas y de comunicación interna y externa.', '["Dar seguimiento a requerimientos administrativos y de coordinación.","Gestionar agenda, reuniones y documentación.","Atender llamadas y correos institucionales.","Apoyar en elaboración de reportes, informes y logística de eventos.","Asistir a la coordinación en tareas operativas y académicas."]'::jsonb, '{"education":"Carrera técnica o licenciatura trunca","experience":"","specialty":"Administración, Comunicación, Educación o afín","languages":"Español, Nivel deseable Ingles A1","knowledge":"Manejo de paquetería Office (Word, Excel, PowerPoint).\nHerramientas de videoconferencia (Google Meet, Zoom).\nRedacción de documentos formales.\nOrganización de archivos físicos y digitales.\nAtención telefónica y digital.","skills":"Organización y planificación\nComunicación verbal y escrita\nAtención al cliente\nTrabajo bajo presión\nMultitareas y seguimiento oportuno","travel":"","sex":""}'::jsonb, 'REPRESENTANTE LEC BAJA CALIFORNIA', NULL)
