INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'AUXILIAR EXÁMENES', 'Auxiliar Exámenes', 'Vacante / Por asignar', 'AUXILIAR', 'operative', 'Brindar apoyo administrativo, logístico y operativo en la planificación, organización, ejecución, validación, recepción y envío de exámenes, así como en la gestión de certificados y documentación correspondiente. Todo ello con el propósito de asegurar el cumplimiento de los procedimientos establecidos por la organización y los organismos certificadores, garantizando la calidad y trazabilidad en cada etapa del proceso.', '["Apoyar en la preparación y distribución de los materiales de examen.","Revisar el inventario de exámenes y materiales de evaluación.","Gestionar la recepción y entrega de exámenes aplicados.","Apoyar en el control y archivo de certificados emitidos.","Registrar y mantener actualizados los reportes de aplicaciones de exámenes.","Coordinar con los aplicadores el calendario y la logística de aplicación de exámenes.","Asistir en la atención de auditorías documentales.","Colaborar en la elaboración de reportes e indicadores mensuales.","Apoyar en la gestión de comunicación con candidatos, aplicadores y partes interesadas.","Participar en las capacitaciones y actualizaciones que la organización determine.","Dar soporte en el seguimiento a incidentes menores durante la aplicación de exámenes.","Asistir en actividades de mejora continua y cumplimiento de requisitos normativos."]'::jsonb, '{"education":"Carrera técnica, Profesional Técnico, o Licenciatura trunca","experience":"1 años","specialty":"Administración, Educación, Pedagogía,Negocios Internacionales o afín","languages":"Inglés Nivel A2 deseable (Marco Común de Referencia Europeo)","knowledge":"Manejo de documentos académicos, control de archivos y expedientes.\r\nConocimientos básicos de los procesos de evaluación y certificación.\r\nFamiliaridad con el uso de plataformas digitales de gestión educativa.\r\nConocimientos básicos de normas de calidad (ISO 9001 e ISO 21001) deseables.\r\nConocimiento de atención a personas.","skills":"Organización, gestion de tiempo  y control documental.\r\nComunicacion efectiva (verbal y escrita).\r\nManejo de herramientas ofimáticas (MS Office, especialmente Excel y Word).\r\nAtención al detalle.\r\nAdaptabilidad.\r\nTrabajo en equipo.\r\nÉtica profesional.\r\nDiscreción y manejo de información confidencial.","travel":"Si","sex":"Indistinto"}'::jsonb, 'COORDINADORA DE EXÁMENES', 'PROC_EXAMENES')
