INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'AUXILIAR FERIA DE LIBRO', 'Auxiliar Feria de Libro', 'Vacante / Por asignar', 'AUXILIAR', 'operative', 'Apoyar en la organización y ejecución de las ferias del libro para la venta de libros y/o 
material didáctico, verificando la atención y logística necesaria para asegurar 
un eficiente desarrollo del eventoen las instituciones.', '["Registrar y mantener actualizado el inventario de libros disponibles en la feria, incluyendo información como título, autor, editorial y cantidad disponible.","Organizar y clasificar los libros en las áreas designadas, asegurando que estén correctamente etiquetados y fácilmente accesibles.","Realizar inventarios periódicos para verificar el stock y realizar ajustes en caso necesario.","Colaborar con el coordinador de la feria para identificar libros faltantes o en baja cantidad y coordinar su reposición.","Asistir en la instalación y desmontaje de stands, ayudando a montar y desmontar la exhibición de libros y otros materiales promocionales.","Apoyar en la organización y decoración de los espacios de la feria, asegurando que estén limpios y ordenados.","Brindar información y asistencia a los visitantes de la feria, respondiendo preguntas sobre los libros disponibles, horarios y actividades programadas.","Ayudar en la atención y venta de libros, ofreciendo recomendaciones, cobrando y registrando las transacciones de manera precisa.","Colaborar en la elaboración de la lista de libros mas vendidos, tomando en cuenta las preferencias de los organizadores y las demandas del público objetivo.","Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso.","Colaborar en la participación de los alumnos con discapacidad.","Potenciar el desarrollo de las capacidades de los alumnos con necesidades educativas especiales.","Promover la inclusión de los alumnos con necesidades específicas","Ofrecer recursos para adaptar y mejorar proceso de aprendizaje.","Garantizar el enfoque a los estudiantes, partes interesadas durante la aplicacion de examenes.","Mantener una comunicacion acertivamente con coordinacion de Examenes, Gerencia de Proyectos y partes interesadas."]'::jsonb, '{"education":"Preparatoria","experience":"","specialty":"Indistinta","languages":"Español, Nivel deseable Ingles A1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"En el manejo de inventarios, incluyendo técnicas de conteo, control y organización.\r\nFamiliaridad con herramientas y software de punto de venta, así como habilidades básicas en el manejo de cajas registradoras y sistemas de pago.\r\nDe técnicas de atención al cliente, incluyendo la capacidad de proporcionar un servicio amable, informativo y personalizado.\r\nConocimiento sobre los recursos relativos a la atención a personas con discapacidad.\r\nConocimientos sobre las posibles barreras de participación de los alumnos con discapacidad.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"","sex":""}'::jsonb, NULL, 'PROC_FERIA_LIBRO')
