INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'AUXILIAR DE SERVICIOS GENERALES', 'Auxiliar de Servicios Generales', 'Vacante / Por asignar', 'AUXILIAR', 'operative', 'Responsable de dar apoyo al puesto de Inventario en la gestión efectiva y eficiente de los procesos de control de inventario de la empresa, para garantizar la exactitud y disponibilidad del inventario de la empresa en todo momento. Apoyo en actividades de mantenimiento que se le requieran.', '["Apoyar al Responsable de Inventario en la gestión y control de inventario.","Realizar la recepción, almacenamiento y recolección de materiales que requiera la empresa.","Actividades de limpieza y mantenimiento de las instalaciones de la empresa.","Colaborar con otros departamentos de la empresa, incluyendo compras, finanzas, producción y logística.","Participar en las actividades de ESR que se le asignen.                                                                                                    Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Secundaria","experience":"","specialty":"Indistinto","languages":"Español, Nivel deseable Ingles A1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"En reporte eportes de los desperfectos de las instalaciones, equipos y mobiliarios para su reparación y mantenimiento. En realización de tareas relacionadas al puesto que sean encomendadas. En operar y controlar las herramientas y equipos de mantenimiento.","skills":"Manejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)\nManejo de herramientas y equipo de mantenimiento.","travel":"","sex":""}'::jsonb, NULL, 'PROC_RRHH')
