INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'COORDINADOR ACADÉMICO', 'Coordinador Académico', 'Vacante / Por asignar', 'COORDINADOR', 'coordination', 'Garantizar la excelencia académica y el cumplimiento de los objetivos educativos de la organización, coordinando y supervisando las actividades académicas y el desarrollo de los programas de enseñanza.
Diseñar cursos de fortalecimiento académico para academias de inglés y afines a su experiencia y/o contratar a diseñadores de cursos en otras áreas según la solicitud de preparación a través de cursos, talleres y/o conferencias de los clientes. 
Seleccionar instructores con el perfil correcto y comprobable para impartición de los cursos solicitados.', '["Diseñar, implementar y evaluar programas académicos que cumplan con los estándares de calidad y las necesidades de los clientes.","Coordinar y supervisar equipos de instructores, brindando apoyo, capacitación y retroalimentación para la entrega de cursos, talleres y/o conferencias que se soliciten.","Establecer políticas y procedimientos relacionados con la planificación curricular, evaluación y seguimiento los mismos.","Realizar seguimiento y evaluación del desempeño de los docentes, asegurando la calidad de la enseñanza y la mejora continua.","Colaborar con otros departamentos para asegurar la integración de las actividades académicas con otros aspectos de la organización.","Promover un ambiente de aprendizaje inclusivo y estimulante para los estudiantes.","Evaluar y seleccionar recursos educativos y materiales didácticos adecuados para los programas académicos.","Mantener una comunicación efectiva con los instructores y las otras áreas.","Monitorear y reportar indicadores de satisfacción de cursos impartidos, evaluación docente, estadísticas de alcance e impacto de los programas solicitados por el cliente.","Mantenerse actualizado sobre las tendencias y avances en educación, asistiendo a conferencias y capacitaciones pertinentes.","Atender auditorías aplicables.","Participar en las actividades de ESR que se le asignen.","Colaborar en la participación de los alumnos con discapacidad.","Potenciar el desarrollo de las capacidades de los alumnos con necesidades educativas especiales.","Promover la inclusión de los alumnos con necesidades específicas","Ofrecer recursos para adaptar y mejorar proceso de aprendizaje.","Garantizar el enfoque a los estidiantes, partes interesadas durante la aplicacion de examenes.","Mantener una comunicacion acertivamente con coordinacion de Examenes, Gerencia de Proyectos y partes interesadas.","Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Licenciatura o Maestría","experience":"2 años","specialty":"Educación o Enseñanza del Inglés o afín","languages":"Español, Nivel deseable Ingles B2 MCRE ( Marco Común de Referencia Europeo)","knowledge":"En las normas y regulaciones educativas aplicables en la región.\r\nDe procesos de acreditación y certificación de idioma.\r\nPedagógicos: Tener una sólida comprensión de los principios y teorías educativas, así como de los métodos de enseñanza y evaluación.\r\nPlanificación curricular: Saber diseñar y desarrollar planes de estudio, programas académicos y actividades de aprendizaje que se ajusten a los estándares educativos y a las necesidades de los estudiantes. \r\nConocimiento sobre los recursos relativos a la atención a personas con discapacidad.\r\nConocimientos sobre las posibles barreras de participación de los alumnos con discapacidad.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams, Zoom.\r\nManejo de herramientas de presentación como Google Slides, Prezi.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de herramientas educativas como PowerSchool, Infinite Campus, Canvas, Blackboard, Moodle, Google Classroom.\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"Si","sex":"Indistinto"}'::jsonb, 'DIRECTOR GENERAL', 'SUBPROC_COORD_ACADEMICA')
ON CONFLICT (org_id, node_id) DO UPDATE SET
    role_title = EXCLUDED.role_title,
    mission = EXCLUDED.mission,
