    process_id = EXCLUDED.process_id,
    updated_at = NOW();

INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'COORDINADORA DE CALIDAD Y RESPONSABILIDAD SOCIAL', 'Coordinadora de Calidad y Responsabilidad Social', 'Vacante / Por asignar', 'COORDINADORA', 'coordination', 'Promover e implementar políticas y prácticas de Responsabilidad Social Empresarial (RSE), así como garantizar el cumplimiento de normas y estándares nacionales e internacionales como ISO y ESR, siempre procurando la satisfacción de las partes interersadas (clientes, estudiantes, comunidad, colaboradores internos y externos, etc.). Liderar la gestión estratégica del talento humano mediante procesos de atracción, desarrollo, bienestar y cultura organizacional, integrando la sostenibilidad, el cumplimiento normativo y la mejora continua en todos los niveles de la organización.', '["Coordinar e implementar programas de RSE alineados a los objetivos estratégicos.","Supervisar el cumplimiento de normas ISO y coordinar auditorías internas y externas.","Elaborar y presentar informes de desempeño en RSE, ISO y procesos de talento humano.","Capacitar y sensibilizar al personal en temas de sostenibilidad, ética, derechos humanos e inclusión.","Gestionar procesos de atracción, desarrollo y retención del talento.","Coordinar programas de bienestar, cultura y clima laboral.","Diseñar e implementar KPIs para RH y sistemas de gestión de calidad.","Fomentar la mejora continua y la alineación de valores institucionales.","Representar a la organización ante organismos certificadores y cámaras empresariales."]'::jsonb, '{"education":"Licenciatura o Maestría","experience":"3 años","specialty":"Administración, Gestión Empresarial, Ingeniería Industrial o afín","languages":"Español, Nivel deseable Ingles B1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Normativas y estándares ISO (9001, 21001) y su aplicación en la organización.\r\nPrincipios y estrategias de RSE y sostenibilidad corporativa.\r\nGestión de sistemas de calidad y mejora continua.\r\nMarco legal laboral mexicano y mejores prácticas en Recursos Humanos.\r\nDesarrollo de KPIs para RH, ISO y desempeño organizacional.\r\nEvaluación y mejora de clima organizacional y cultura corporativa.","skills":"Comunicación oral y escrita efectiva.\r\nLiderazgo ético con enfoque humano.\r\nPensamiento estratégico y enfoque en resultados.\r\nPlaneación, organización y gestión del tiempo.\r\nCapacidad de análisis y toma de decisiones informadas.\r\nTrabajo colaborativo y gestión transversal.\r\nManejo de herramientas digitales (Google Workspace, Microsoft Office, Zoom, Teams, etc.).","travel":"Si","sex":"Indistinto"}'::jsonb, 'DIRECTOR GENERAL', 'SUBPROC_AUDITORIAS_INTERNAS')
ON CONFLICT (org_id, node_id) DO UPDATE SET
