INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'COORDINADORA DE EXÁMENES', 'Coordinadora de Exámenes', 'Vacante / Por asignar', 'COORDINADORA', 'coordination', 'Coordinar el desarrollo de las actividades de aplicación de exámenes para las certificaciones 
de enseñanza y aprendizaje del idioma inglés, verificando y validando el cumplimiento de los 
estándares internacionales que demandan los organismos representativos.', '["Garantizar que las aplicaciones de exámenes se desarrollen sin problemas:","Coordinar y supervisar el proceso de aplicación de exámenes, asegurando que se sigan los procedimientos establecidos y se cumplan los requisitos de seguridad y confidencialidad.","Preparar y distribuir el material de prueba a los aplicadores y supervisores designados, asegurando que esté completo y en condiciones adecuadas.","Realizar un seguimiento continuo durante las aplicaciones de exámenes para identificar y resolver cualquier problema o inconveniente que pueda surgir.","Establecer una comunicación regular y efectiva con International House, para informar sobre cualquier cambio, imprevisto o situación relevante que surja durante la coordinación de los exámenes.","Proporcionar actualizaciones oportunas sobre el progreso de las aplicaciones de exámenes y cualquier problema que requiera atención por parte de International House.","Supervisar el proceso de recepción de los exámenes enviados por International House, asegurando que se reciban correctamente y que coincidan con las aplicaciones realizadas.","Identificar y resolver cualquier discrepancia o problema que surja al recibir los exámenes, como daños en el material o errores en la documentación adjunta.","Evaluar y seleccionar cuidadosamente a los aplicadores y supervisores de exámenes, asegurándose de que cumplan con los requisitos de competencia y capacitación establecidos.","Proporcionar una orientación clara y detallada sobre las responsabilidades y procedimientos a seguir durante las aplicaciones de exámenes, asegurando que los aplicadores estén debidamente preparados.","Coordinar el envío seguro y oportuno de los exámenes completados a Cambridge Assessment English u otras entidades responsables, siguiendo los procedimientos y requisitos establecidos.","Asegurar la recepción y gestión adecuada de los certificados emitidos por Cambridge Assessment English u otras entidades responsables, asegurando su custodia y distribución correcta a los candidatos.","Mantener un registro preciso y seguro de todos los certificados y exámenes recibidos y enviados, asumiendo la responsabilidad de su custodia y evitando cualquier pérdida o extravío.","Atender auditorías aplicables","Participar en las actividades de ESR que se le asignen","Presentar indicadores mensuales.","Colaborar en la participación de los alumnos con discapacidad.","Potenciar el desarrollo de las capacidades de los alumnos con necesidades educativas especiales.","Promover la inclusión de los alumnos con necesidades específicas","Ofrecer recursos para adaptar y mejorar proceso de aprendizaje.","Garantizar el enfoque a los estidiantes, partes interesadas durante la aplicacion de examenes.","Mantener una comunicacion acertivamente con coordinacion de Examenes, Gerencia de Proyectos y partes interesadas.","Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Licenciatura o Carrera Trunca","experience":"2 años","specialty":"Enseñanza del Inglés, Educación y/o Pedagogía o afín","languages":"Español, Nivel deseable Ingles B2 MCRE ( Marco Común de Referencia Europeo)","knowledge":"De los sistemas y metodologías de evaluación y exámenes utilizados en el ámbito educativo.\r\nFamiliaridad con las tecnologías de evaluación en línea y la administración de exámenes electrónicos.\r\nComprensión de los principios de validación y confiabilidad de los exámenes.\r\nDe los requisitos y estándares académicos establecidos por instituciones educativas o entidades reguladoras.\r\nConocimiento sobre los recursos relativos a la atención a personas con discapacidad.\r\nConocimientos sobre las posibles barreras de participación de los alumnos con discapacidad.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams, Zoom.\r\nManejo de herramientas de presentación como Google Slides, Prezi.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de herramientas educativas como PowerSchool, Infinite Campus, Canvas, Blackboard, Moodle, Google Classroom.\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"Si","sex":"Indistinto"}'::jsonb, 'GERENTE DE OPERACIONES', 'PROC_EXAMENES')
