INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'COORDINADORA DE PROYECTOS', 'Coordinadora de Proyectos', 'Vacante / Por asignar', 'COORDINADORA', 'coordination', 'Liderar y supervisar la ejecución exitosa de proyectos, asegurando el cumplimiento de los objetivos, plazos y recursos asignados. 
Promoviendo la eficiencia, calidad y satisfacción del cliente en cada proyecto, aplicando buenas prácticas de gestión y fomentando la colaboración y comunicación efectiva entre los miembros del equipo.', '["Definir los objetivos, alcance, plazos y recursos necesarios para cada proyecto.","Elaborar planes de proyecto detallados, incluyendo la secuencia de actividades, asignación de tareas y estimación de recursos.","Realizar seguimiento regular del avance del proyecto, identificando desviaciones y tomando acciones correctivas según sea necesario.","Coordinar reuniones de seguimiento y presentar informes de progreso relevantes.","Facilitar la comunicación y colaboración efectiva entre los miembros del equipo, fomentando un ambiente de trabajo positivo y motivador.","Identificar y asegurar los recursos necesarios para la ejecución exitosa del proyecto, incluyendo personal, equipos, materiales y proveedores externos.","Realizar seguimiento y control del presupuesto asignado al proyecto, asegurando un uso eficiente de los recursos y gestionando adecuadamente los costos.","Coordinar la resolución de problemas, facilitando la colaboración entre los miembros del equipo y tomando decisiones oportunas para minimizar el impacto en el proyecto.","Atender auditorías aplicables","Participar en las actividades de ESR que se le asignen.","Colaborar en la participación de los alumnos con discapacidad.","Potenciar el desarrollo de las capacidades de los alumnos con necesidades educativas especiales.","Promover la inclusión de los alumnos con necesidades específicas","Ofrecer recursos para adaptar y mejorar proceso de aprendizaje.","Garantizar el enfoque a los estudiantes, partes interesadas durante la aplicacion de examenes.","Mantener una comunicacion acertivamente con coordinacion de Examenes, Gerencia de Proyectos y partes interesadas.","Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Licenciatura / Carrera Técnica","experience":"1 año","specialty":"Administración, Finanzas, Project Managment o afín","languages":"Español, Nivel deseable Ingles B1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Comprensión de las técnicas y herramientas de gestión de proyectos.\r\nDe los principios de control de calidad y aseguramiento de la calidad en la gestión de proyectos.\r\nComprensión de los conceptos financieros básicos relacionados con la gestión de proyectos, como presupuestos, costos y rentabilidad.\r\nConocimiento sobre los recursos relativos a la atención a personas con discapacidad.\r\nConocimientos en sistemas  alternativos de comunicación (Lenguaje de Señas, Lectura Braille, etc.).\r\nConocimientos sobre las posibles barreras de participación de los alumnos con discapacidad.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams, Zoom.\r\nManejo de herramientas de presentación como Google Slides, Prezi.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"Si","sex":"Indistinto"}'::jsonb, 'DIRECTOR GENERAL', 'SUBPROC_GESTION_PROYECTOS')
