INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'DIRECTOR GENERAL', 'Director General', 'Vacante / Por asignar', 'DIRECTOR', 'directive', 'Dirigir y liderar la eficiente operación de Languages and Education Consulting (LEC) para el logro de los objetivos de la organización con una visión enfocada en la calidad, proyección positiva hacia la comunidad y utilidad financiera proyectada, asegurando el cumplimiento de los estándares internacionales establecidos por los organismos representativos.', '["Planificar, evaluar y dar seguimiento a los procesos de LEC, asegurando la calidad y eficiencia de los servicios brindados.","Fijar y dirigir, de acuerdo a los objetivos y prioridades de LEC, la operación general de la organización.","Dirigir, organizar y proporcionar los servicios de consultoría educativa, estableciendo altos estándares de calidad.","Autorizar cotizaciones y adquisiciones de bienes y servicios necesarios para el desarrollo de las actividades de LEC.","Autorizar el gasto y garantizar la correcta administración de los recursos financieros.","Elaborar y autorizar contratos de prestación de servicios, asegurando la correcta ejecución y cumplimiento de los mismos.","Presidir las reuniones de LEC y autorizar los acuerdos resultantes de las mismas.","Atender auditorías aplicables","Participar en las actividades de ESR que se le asignen                                                                                                Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Licenciatura o Maestría","experience":"5 años","specialty":"Educación, Enseñanza del Inglés, Administración y afin.","languages":"Español, Nivel deseable Ingles C1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"En administración y gestión empresarial.\r\nDe contabilidad para el seguimiento financiero y control presupuestario.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams, Zoom.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\n\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"Si","sex":"Indistinto"}'::jsonb, NULL, 'PROC_RRHH')
