INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'DISEÑADOR Y DESARROLLADOR WEB', 'Diseñador y Desarrollador Web', 'Vacante / Por asignar', 'DISEÑADOR', 'operative', 'Crear y mantener sitios web atractivos, funcionales y efectivos para nuestros clientes. Debe combinar habilidades creativas y técnicas para diseñar y desarrollar interfaces web intuitivas y optimizadas, asi como tambien desarollo y mantenimiento de sistemas informaticos en base a las necesidades de la empresa, brindando experiencias del agrado de los usuarios.', '["Diseñar, desarrollar y mantener acutalizados sitios web interactivos y atractivos, asi como tambien el material grafico y multimedia requerido siguiendo los requisitos y directrices de la empresa.","Crear interfaces de usuario intuitivas y optimizadas para mejorar la experiencia del usuario.","Optimizar los sitios web para mejorar su rendimiento, velocidad de carga y capacidad de respuesta.","Colaborar con diseñadores gráficos y equipos de desarrollo para garantizar la coherencia visual y técnica en el diseño y desarrollo de los sitios web.","Mantenerse al día con las últimas tendencias y avances en diseño web y desarrollo, y aplicarlos de manera efectiva en los proyectos.","Solucionar problemas técnicos y resolver errores en los sitios web existentes.","Realizar pruebas de usabilidad y obtener retroalimentación de los usuarios para mejorar continuamente los sitios web.","Atender auditorías aplicables","Participar en las actividades de ESR que se le asignen                                                                                                    Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Licenciatura o Carrera Tecnica","experience":"2 años","specialty":"Diseño grafico, Sistemas computacionales, Diseño web o afín.","languages":"Español, Nivel deseable Ingles A1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Conocimiento de lenguajes de programación web como HTML, CSS, PHP y JavaScript.\r\nExperiencia en el uso de herramientas y frameworks de diseño web, como Bootstrap, jQuery, etc.\r\nConocimientos de diseño gráfico, incluyendo el uso de software como Adobe Photoshop, Illustrator, Corel Draw u otros programas similares.\r\nFamiliaridad con conceptos de usabilidad y experiencia de usuario (UX).\r\nConocimientos de SEO (Optimización de Motores de Búsqueda) para garantizar que los sitios web sean fáciles de encontrar en los motores de búsqueda.\r\nCapacidad para trabajar con sistemas de gestión de contenido (CMS) como WordPress, Drupal, Joomla, etc.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams, Zoom.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"Si","sex":"Indistinto"}'::jsonb, 'GERENTE DE OPERACIONES', NULL)
