VALUES ((SELECT id FROM public.organizations LIMIT 1), 'EJECUTIVO DE VENTAS', 'Ejecutivo de ventas', 'Vacante / Por asignar', 'EJECUTIVO', 'operative', 'Captar clientes y nuevas oportunidades de negocio, identificando las necesidades e intereses de clientes potenciales con la finalidad de crear relaciones de trabajo a corto y largo plazo que den soporte a los objetivos de la organización', '["Llevar a cabo estrategias de ventas para el logro metas.","Realizar llamadas y visitas de prospección y/o seguimiento a clientes.","Envió de cotizaciones según la detección de oportunidades.","Seguimiento a necesidades y requerimientos de clientes.","Gestionar y actualizar la base de datos de clientes y prospectos.","Gestionar y cumplir con el proceso de ventas","Atender auditorías aplicables.","Participar en las actividades de ESR que se le asignen.","Presentar indicadores mensuales.                                                                                                                                       Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Licenciatura o carrera técnica","experience":"2 años","specialty":"Administración y/o Ventas","languages":"Español, Nivel deseable Ingles B1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"De técnicas de ventas y habilidades de negociación.\r\nDe los principios y procesos de atención al cliente.\r\nDe técnicas de prospección.\r\nDe los canales de venta y de estrategias de marketing.\r\nDe los sistemas y herramientas de gestión de ventas.\r\nDe los procesos de seguimiento postventa y fidelización de clientes.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace, Microsoft Teams, Zoom.\r\nManejo de herramientas de presentación como Google Slides, Prezi.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de herramientas de gestion de recursos como Admintotal\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"Si","sex":"Indistinto"}'::jsonb, 'GERENTE DE OPERACIONES', 'PROC_VENTAS')
