INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'ENLACE DE SISTEMA INTEGRAL', 'Enlace De Sistema Integral', 'Vacante / Por asignar', 'ENLACE', 'operative', 'Asegurar la integración adecuada, el seguimiento continuo y la operación eficiente de los sistemas tecnológicos y plataformas digitales de la organización, actuando como un vínculo eficaz y brindando soporte a las áreas que conforman el Sistema Integral y las herramientas digitales, con el fin de garantizar que estos sistemas respalden los objetivos estratégicos y operativos de la organización', '["Coordinar la integración, operación y seguimiento de los sistemas y plataformas tecnológicas de la empresa.","Servir como enlace y punto de contacto entre las áreas del sistema integral, calidad, operaciones y otras áreas clave.","Verificar que los sistemas cumplan con los requerimientos técnicos, operativos y normativos aplicables.","Apoyar en auditorías internas y externas relacionadas con sistemas tecnológicos y calidad.","Documentar procesos, evidencias y procedimientos relacionados con la gestión tecnológica.","Coordinar y apoyar acciones correctivas y mejoras tecnológicas en colaboración con áreas involucradas.","Brindar soporte, capacitación básica y difusión sobre el uso correcto de sistemas y normativas aplicables."]'::jsonb, '{"education":"Licenciatura, Ingeniería, o Carrera Trunca","experience":"Deseable 1 año","specialty":"Tecnologías de la Información, Sistemas de Gestión de Calidad, o afines","languages":"Español, deseable Inglés nivel B1 MCRE","knowledge":"Normas ISO 9001:2015 e ISO 21001:2018\r\nPlataformas tecnológicas empresariales\r\nProcesos de auditoría y control de calidad\r\nDocumentación y control de procedimientos\r\nFundamentos de tecnologías de la información y gestión de proyectos","skills":"Capacidad de análisis \r\nComunicación efectiva y trabajo en equipo\r\nResolución de problemas\r\nOrganización y gestión del tiempo\r\nAtención al detalle\r\nProactividad y orientación al servicio Trabajo en equipo.","travel":"Si","sex":"Indistinto"}'::jsonb, 'COORDINADORA DE CALIDAD Y RESPONSABILIDAD SOCIAL', 'PROC_FINANZAS')
