INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'GERENTE DE ADMINISTRACIÓN Y FINANZAS', 'Gerente de Administración y Finanzas', 'Vacante / Por asignar', 'GERENTE', 'directive', 'Planificar, dirigir y controlar los recursos financieros, administrativos y de compras de la organización, asegurando la adquisición eficiente de bienes y servicios, optimizando los recursos y garantizando el cumplimiento de los objetivos estratégicos. Desarrollar relaciones sólidas con proveedores, gestionar presupuestos y aplicar controles internos que aseguren el buen funcionamiento financiero y operativo de la empresa.', '["Planear y controlar el presupuesto general","Identificar necesidades de compras y gestionar adquisiciones","Negociar con proveedores y asegurar relaciones sólidas","Supervisar el cumplimiento de normativas fiscales y contables","Analizar costos y realizar comparativas para toma de decisiones","Supervisar y controlar inventarios, pagos, caja chica y viáticos","Elaborar contratos, informes y estados financieros","Presentar indicadores mensuales y reportes financieros","Atender auditorías internas y externas","Gestionar riesgos administrativos y financieros","Implementar mejoras en procesos administrativos y de compras","Participar en actividades de Responsabilidad Social Empresarial (ESR)","Asegurar el desempeño del SGC y SGOE según normas ISO"]'::jsonb, '{"education":"Licenciatura","experience":"","specialty":"Contabilidad, Administración, Finanzas o afin","languages":"Español, Nivel deseable Ingles A1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Procesos de compras y cadena de suministro\r\nTécnicas de negociación\r\nAnálisis financiero, contable y presupuestario\r\nLegislación fiscal, comercial y laboral mexicana\r\nPlaneación estratégica y control interno\r\nGestión administrativa, financiera y contable\r\nSistemas de información financiera y ERP (como AdminTotal)","skills":"Comunicación efectiva (verbal y escrita)\r\nLiderazgo y gestión de equipos\r\nManejo de herramientas de oficina (Word, Excel, PowerPoint)\r\nManejo de herramientas de videoconferencia (Google Workspace, Teams, Zoom)\r\nManejo de herramientas de comunicación digital (email, mensajería instantánea)\r\nManejo de herramientas contables y de gestión (AdminTotal, software contable)\r\nCapacidad de análisis, negociación y resolución de problemas","travel":"","sex":""}'::jsonb, 'DIRECTOR GENERAL', 'PROC_FINANZAS')
ON CONFLICT (org_id, node_id) DO UPDATE SET
    role_title = EXCLUDED.role_title,
    mission = EXCLUDED.mission,
    responsibilities = EXCLUDED.responsibilities,
    requirements = EXCLUDED.requirements,
    parent_node_id = EXCLUDED.parent_node_id,
    process_id = EXCLUDED.process_id,
    updated_at = NOW();

INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'GERENTE DE OPERACIONES', 'Gerente de Operaciones', 'Vacante / Por asignar', 'GERENTE', 'directive', 'Coordinar de manera adecuada cada una de las áreas que integran la empresa con el objetivo de asegurar el cumplimiento de las responsabilidades de las coordinaciones y los objetivos de la organización.', '["Dar seguimiento a los pagos de clientes y proveedores, garantizando el cumplimiento de los plazos establecidos.","Supervisar y asegurar que los procesos internos se lleven a cabo correctamente, identificando oportunidades de mejora y aplicando acciones correctivas cuando sea necesario.","Gestionar los recursos necesarios para las diferentes áreas y coordinaciones de la empresa, asegurando un uso eficiente y óptimo.","Dar seguimiento y evaluar el avance de las actividades y proyectos en curso, asegurando su cumplimiento en tiempo y forma.","Mantener una comunicación efectiva con el equipo de trabajo, brindando orientación, apoyo y retroalimentación.","Participar en la toma de decisiones estratégicas y en la planificación de metas y objetivos a corto y largo plazo.","Representar a la empresa ante clientes, proveedores y otros actores externos, manteniendo relaciones comerciales sólidas y gestionando posibles conflictos.","Mantenerse actualizado sobre las tendencias y novedades del sector, identificando oportunidades de crecimiento y mejora.","Atender auditorías aplicables","Participar en las actividades de ESR que se le asignen.                                                                                                     Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Licenciatura o Carrera Trunca","experience":"1 año","specialty":"Educación, Enseñanza del Inglés, Administración o afin.","languages":"Español, Nivel deseable Ingles B1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Comprension de certificaciones y normativas relacionadas con la industria o sector específico de la empresa.     En administración organizacional.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace, Microsoft Teams, Zoom.   \r\nManejo de herramientas de presentación como Google Slides, Prezi.                                                                   Manejo de personal.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)\r\nManejo de redes sociales (Facebook, Instagram)","travel":"Si","sex":"Indistinto"}'::jsonb, 'DIRECTOR GENERAL', NULL)
ON CONFLICT (org_id, node_id) DO UPDATE SET
    role_title = EXCLUDED.role_title,
    mission = EXCLUDED.mission,
    responsibilities = EXCLUDED.responsibilities,
    requirements = EXCLUDED.requirements,
    parent_node_id = EXCLUDED.parent_node_id,
    process_id = EXCLUDED.process_id,
    updated_at = NOW();

INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'INSTRUCTOR', 'Instructor', 'Vacante / Por asignar', 'INSTRUCTOR', 'operative', 'Brindar una experiencia educativa de alta calidad a los participantes, proporcionando conocimientos y habilidades en el campo de enseñanza de idiomas. 
Asegurar un ambiente de aprendizaje efectivo, motivador y enriquecedor para los participantes.', '["Impartir clases de manera efectiva, siguiendo el plan de estudios establecido.","Preparar y entregar material didáctico de calidad, adaptado a las necesidades y niveles de los participantes.","Evaluar y realizar un seguimiento del progreso de los participantes, brindando retroalimentación constructiva.","Estimular la participación activa de los participantes, fomentando un ambiente de aprendizaje dinámico y colaborativo.","Mantenerse actualizado en los avances y tendencias en la enseñanza, participando en actividades de desarrollo profesional y capacitación.","Participar en reuniones de equipo y colaborar con otros instructores para mejorar la calidad de la enseñanza.","Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso.","Colaborar en la participación de los alumnos con discapacidad.","Potenciar el desarrollo de las capacidades de los alumnos con necesidades educativas especiales.","Promover la inclusión de los alumnos con necesidades específicas","Ofrecer recursos para adaptar y mejorar proceso de aprendizaje.","Garantizar el enfoque a los estidiantes, partes interesadas durante la aplicacion de examenes.","Mantener una comunicacion acertivamente con coordinacion de Examenes, Gerencia de Proyectos y partes interesadas."]'::jsonb, '{"education":"Licenciatura o Maestría","experience":"3 años","specialty":"Educación, Enseñanza del Inglés u otra especialización según el tipo de curso solicitado.","languages":"Español, Nivel deseable Ingles B1 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Habilidades de comunicación (verbal y escrita)\r\nFamiliaridad con las metodologías y enfoques pedagógicos más actualizados en el área de especialización que requiera el curso, taller y/o conferencia solicitado.\r\nConocimiento sobre los recursos relativos a la atención a personas con discapacidad.\r\nConocimientos sobre las posibles barreras de participación de los alumnos con discapacidad.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams, Zoom.\r\nManejo de herramientas de presentación como Google Slides, Prezi.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)","travel":"Si","sex":"Indistinto"}'::jsonb, 'COORDINADOR ACADÉMICO', 'PROC_ACADEMICA')
ON CONFLICT (org_id, node_id) DO UPDATE SET
    role_title = EXCLUDED.role_title,
    mission = EXCLUDED.mission,
    responsibilities = EXCLUDED.responsibilities,
    requirements = EXCLUDED.requirements,
    parent_node_id = EXCLUDED.parent_node_id,
    process_id = EXCLUDED.process_id,
    updated_at = NOW();

INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'PRACTICANTE', 'Practicante', 'Vacante / Por asignar', 'PRACTICANTE', 'operative', 'Brindar apoyo y asistencia en proyectos relacionados con la optimización de procesos y el desarrollo de estrategias para mejorar la eficiencia y efectividad del sistema de gestión de la empresa.', '["Colaborar en la identificación de oportunidades de mejora en los procesos y procedimientos existentes.","Asistir en la documentación y estandarización de los procesos y políticas de la empresa.","Participar en la elaboración de indicadores clave de desempeño (KPIs) y en el seguimiento de su cumplimiento.","Apoyar en la implementación de acciones correctivas y preventivas para abordar no conformidades o desviaciones identificadas.","Colaborar en la realización de auditorías internas para evaluar el cumplimiento de los estándares de calidad y proponer recomendaciones de mejora.","Participar en la capacitación del personal en temas relacionados con la gestión de calidad y la mejora continua.","Realizar el seguimiento de los planes de acción y las metas establecidas en el sistema de gestión.              Conocimiento relativo al proyecto para el que se le contrata.","Atender auditorías aplicables.","Participar en las actividades de ESR que se le asignen.                                                                                                      Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso."]'::jsonb, '{"education":"Estudiante de Licenciatura.","experience":"No requerido","specialty":"La que requiera el proyecto.","languages":"Español, Nivel deseable Ingles A2 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Familiardiad en los principios y conceptos de gestión de calidad, como ISO 9001 u otros estándares similares.\r\nFamiliaridad con herramientas y técnicas para el análisis de procesos, como diagramas de flujo, diagramas de causa y efecto, y análisis FODA.\r\nComprensión de los fundamentos de la mejora continua y la resolución de problemas.\r\nComprension de conceptos de logística y cadena de suministro, incluyendo inventario, transporte y distribución.\r\nFamiliaridad con software de Inteligencia Artificial.\r\nDe recursos y tecnologías educativas para la enseñanza de idiomas, incluyendo software de aprendizaje, plataformas en línea y recursos multimedia.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace, Microsoft Teams, Zoom.\r\nManejo de herramientas de presentación como Google Slides, Prezi.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)                                                   Manejo de sofware de Inteligencia Artificial.\r\nManejo de herramientas educativas como PowerSchool, Infinite Campus, Canvas, Blackboard, Moodle, Google Classroom.\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram).\r\nConocimientos acordes a las necesidaes del proyecto del área solicitante.","travel":"No requerido","sex":"Indistinto"}'::jsonb, 'COORDINADORA DE CALIDAD Y RESPONSABILIDAD SOCIAL', NULL)
ON CONFLICT (org_id, node_id) DO UPDATE SET
    role_title = EXCLUDED.role_title,
    mission = EXCLUDED.mission,
    responsibilities = EXCLUDED.responsibilities,
    requirements = EXCLUDED.requirements,
    parent_node_id = EXCLUDED.parent_node_id,
    process_id = EXCLUDED.process_id,
    updated_at = NOW();

INSERT INTO public.hr_profiles (org_id, node_id, role_title, holder_name, area, role_type, mission, responsibilities, requirements, parent_node_id, process_id)
VALUES ((SELECT id FROM public.organizations LIMIT 1), 'REPRESENTANTE LEC BAJA CALIFORNIA', 'Representante LEC Baja California', 'Vacante / Por asignar', 'REPRESENTANTE', 'coordination', 'Proveer excelente servicio al cliente, para apoyar al logro de objetivos y metas de la empresa.  Apoyar en actividades administrativas con excelente actitud cumpliendo los objetivos de la organización.', '["Brindar atención al público interno y externo, asegurando un trato amable y profesional.","Administrar documentos digitales y físicos, asegurando su correcta organización y resguardo.","Recepcionar llamadas telefónicas y correos electrónicos, proporcionando información precisa y resolviendo consultas o derivándolas a los departamentos correspondientes.","Aplicar y gestionar exámenes, asegurando su correcta administración y registro.","Realizar visitas a clientes prospectos, presentando los servicios de la empresa y estableciendo relaciones comerciales.","Resguardar materiales confidenciales de manera segura y confiable.","Realizar seguimiento a clientes, asegurando su satisfacción y atendiendo cualquier inquietud o queja de manera oportuna.","Capacitarse en los diferentes entrenamientos proporcionados para garantizar una correcta ejecución de las aplicaciones y servicios ofrecidos.","Entregar certificados y documentación a los clientes de acuerdo con los procedimientos establecidos.","Atender auditorías aplicables.","Comprender la Politica Integral de la Organización.","Asegurar el cumplimiento de los resultados esperados del SGC y SGOE.","Asegurar el aumento del desempeño del SGC y SGOE de acuerdo a los controles establecidos en el proceso.","Mejorar continuamente el proceso.","Garantizar el enfoque a los estudiantes, partes interesadas durante la ejecucion de las actividades de venta.","Mantener una comunicacion acertivamente con Dirección y partes interesadas.","Conocimientos en sistemas  alternativos de comunicación (Lenguaje de Señas, Lectura Braille, etc.)."]'::jsonb, '{"education":"Licenciatura / Carrera Trunca","experience":"1 año","specialty":"Enseñanza del Inglés, Educación, o afín.","languages":"Español, Nivel deseable Ingles B2 MCRE ( Marco Común de Referencia Europeo)","knowledge":"Comprension de certificaciones y normativas de los diferentes instrumentos y productos que oferta la organización.    \r\nEn administración organizacional.\r\nConocimiento sobre los recursos relativos a la atención a personas con discapacidad.\r\nConocimientos en sistemas  alternativos de comunicación (Lenguaje de Señas, Lectura Braille, etc.).\r\nConocimientos sobre las posibles barreras de participación de los alumnos con discapacidad.","skills":"Comunicación (verbal y escrita)\r\nManejo de herramientas de colaboración (Videoconferencias) en línea como Google Workspace para Educación, Microsoft Teams, Zoom.\r\nManejo de herramientas de presentación como Google Slides, Prezi.\r\nManejo de herramientas de paquete office (Microsoft Word, Excel, Powerpoint)\r\nManejo de heramientas de comunicación digital como correos electrónicos, mensajería instantánea (Whatsapp, Messenger, Telegram)\r\nManejo de redes sociales (Facebook, Instagram)\r\nFamiliaridad con herramientas y software de punto de venta, así como habilidades básicas en el manejo de cajas registradoras y sistemas de pago.","travel":"Si","sex":"Indistinto"}'::jsonb, 'GERENTE DE OPERACIONES', NULL)
