VALUES ((SELECT id FROM public.organizations LIMIT 1), 'RESPONSABLE DE COMUNICACIÓN', 'Responsable de Comunicación', 'Vacante / Por asignar', 'RESPONSABLE', 'operative', 'Diseñar, implementar y mantener estrategias de comunicación interna y externa que fortalezcan la imagen institucional. Gestionar contenidos digitales y redes sociales alineados con los valores y objetivos organizacionales asegurando una presencia digital coherente, profesional y efectiva.', '["Diseñar y ejecutar planes de comunicación interna.","Crear, publicar y monitorear contenido en redes sociales.","Gestionar imagen institucional.","Coordinar campañas de difusión.","Supervisar la reputación institucional.","Producir material visual y audiovisual.","Apoyar en eventos internos y externos."]'::jsonb, '{"education":"Licenciatura, Ingeniería, o Carrera Técnica","experience":"Deseable 1 años","specialty":"Comunicación, Marketing Digital, Gestión Empresarial, Diseño Gráfico, Relaciones Públicas o afín","languages":"Español, deseable Inglés nivel A2-B1 MCRE","knowledge":"Plataformas de redes sociales (Facebook, Instagram, LinkedIn, TikTok, X/Twitter), fotografía y edición básica de video (deseable)","skills":"Comunicación clara (oral y escrita).\r\n Creatividad e innovación.\r\n Análisis estratégico.\r\n Organización y gestión del tiempo.\r\n Trabajo en equipo.\r\n Dominio de herramientas digitales (Google Workspace, Teams, Zoom, etc.)","travel":"Si","sex":"Indistinto"}'::jsonb, 'GERENTE DE OPERACIONES', 'PROC_VENTAS')
